import json
import shlex

def merge_news_and_relate(news, relate):

    # 创建result的副本，避免修改原始数据
    result = news.copy()

    # 添加relevant_news字段（注意字段名是relevant_news）
    result['relevant_news'] = {
        'id': relate['id'],
        'claim': relate['claim'],
        'collection': relate['collection']
    }

    # 将result转换为JSON字符串，确保中文正常显示
    json_str = json.dumps(result, ensure_ascii=False, indent=2)

    # 构建curl命令
    curl_command = f'curl -X POST http://127.0.0.1:8888/api/news -H "Content-Type: application/json" -d {shlex.quote(json_str)}'

    return curl_command

